import requests

headers = {"Authorization": f"Bearer {access_token}", "Content-Type": "application/json"}

policy = {
    "displayName": "Require MFA for Azure Portal",
    "state": "enabled",
    "conditions": {
        "users": {"includeGroups": ["<group-id>"]},
        "applications": {"includeApplications": ["797f4846-ba00-4fd7-ba43-dac1f8f63013"]},  # Azure portal
        "locations": {"includeLocations": ["All"]}
    },
    "grantControls": {
        "operator": "OR",
        "builtInControls": ["mfa"]
    }
}

resp = requests.post(
    "https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies",
    headers=headers, json=policy
)
print(resp.status_code, resp.json().get("id"))

